local SessionManager = {}
SessionManager.__index = SessionManager

function SessionManager.new(config)
    local self = setmetatable({}, SessionManager)
    self.token_length = (config and config.token_length) or 64
    self.nonce_length = (config and config.nonce_length) or 32
    self.token_expiry = (config and config.token_expiry) or 3600
    self.sessions = {}
    return self
end

local function generate_random_hex(length)
    local chars = "0123456789abcdef"
    local result = {}
    for i = 1, length do
        local idx = math.random(1, #chars)
        result[i] = string.sub(chars, idx, idx)
    end
    return table.concat(result)
end

local function generate_random_base62(length)
    local chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789"
    local result = {}
    for i = 1, length do
        local idx = math.random(1, #chars)
        result[i] = string.sub(chars, idx, idx)
    end
    return table.concat(result)
end

function SessionManager:generate_token()
    local timestamp = os.time()
    local random_part = generate_random_base62(self.token_length)
    local entropy = math.random(100000, 999999)
    local token = string.format("%s_%s_%d", random_part, generate_random_hex(16), entropy)
    return token
end

function SessionManager:generate_nonce()
    local nonce_part = generate_random_hex(self.nonce_length)
    local timestamp_hex = string.format("%x", os.time())
    local extra_entropy = math.random(1000000, 9999999)
    local nonce = string.format("%s%s%d", nonce_part, timestamp_hex, extra_entropy)
    return nonce
end

function SessionManager:generate_csrf_token()
    local part1 = generate_random_base62(16)
    local part2 = generate_random_hex(16)
    local part3 = generate_random_base62(16)
    return string.format("%s-%s-%s", part1, part2, part3)
end

function SessionManager:create_session(user_id, metadata)
    local token = self:generate_token()
    local nonce = self:generate_nonce()
    local csrf_token = self:generate_csrf_token()
    local now = os.time()

    local session = {
        token = token,
        nonce = nonce,
        csrf_token = csrf_token,
        user_id = user_id,
        created_at = now,
        expires_at = now + self.token_expiry,
        last_accessed = now,
        metadata = metadata or {},
        is_active = true
    }

    self.sessions[token] = session
    return session
end

function SessionManager:validate_session(token)
    if not token or token == "" then
        return false, "Token is empty or nil"
    end

    local session = self.sessions[token]
    if not session then
        return false, "Session not found"
    end

    if not session.is_active then
        return false, "Session is inactive"
    end

    local now = os.time()
    if now > session.expires_at then
        session.is_active = false
        return false, "Session has expired"
    end

    session.last_accessed = now
    return true, session
end

function SessionManager:refresh_session(token)
    local valid, result = self:validate_session(token)
    if not valid then
        return false, result
    end

    local session = result
    local new_token = self:generate_token()
    local new_nonce = self:generate_nonce()
    local now = os.time()

    session.token = new_token
    session.nonce = new_nonce
    session.expires_at = now + self.token_expiry
    session.last_accessed = now

    self.sessions[token] = nil
    self.sessions[new_token] = session

    return true, session
end

function SessionManager:invalidate_session(token)
    local session = self.sessions[token]
    if session then
        session.is_active = false
        self.sessions[token] = nil
        return true, "Session invalidated"
    end
    return false, "Session not found"
end

function SessionManager:invalidate_user_sessions(user_id)
    local count = 0
    local tokens_to_remove = {}

    for token, session in pairs(self.sessions) do
        if session.user_id == user_id then
            session.is_active = false
            tokens_to_remove[#tokens_to_remove + 1] = token
            count = count + 1
        end
    end

    for _, token in ipairs(tokens_to_remove) do
        self.sessions[token] = nil
    end

    return count
end

function SessionManager:cleanup_expired()
    local now = os.time()
    local count = 0
    local tokens_to_remove = {}

    for token, session in pairs(self.sessions) do
        if now > session.expires_at or not session.is_active then
            tokens_to_remove[#tokens_to_remove + 1] = token
            count = count + 1
        end
    end

    for _, token in ipairs(tokens_to_remove) do
        self.sessions[token] = nil
    end

    return count
end

function SessionManager:get_active_session_count()
    local count = 0
    local now = os.time()
    for _, session in pairs(self.sessions) do
        if session.is_active and now <= session.expires_at then
            count = count + 1
        end
    end
    return count
end

function SessionManager:get_user_sessions(user_id)
    local user_sessions = {}
    local now = os.time()
    for _, session in pairs(self.sessions) do
        if session.user_id == user_id and session.is_active and now <= session.expires_at then
            user_sessions[#user_sessions + 1] = {
                token = session.token,
                created_at = session.created_at,
                expires_at = session.expires_at,
                last_accessed = session.last_accessed
            }
        end
    end
    return user_sessions
end

